#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int A1, A2, B1, B2;
        scanf("%d %d %d %d", &A1, &A2, &B1, &B2);
        int sum = (A1 - A2) + (B1 - B2);
        if (sum < 0) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

