import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            st = new StringTokenizer(br.readLine());
            long A1 = Long.parseLong(st.nextToken());
            long A2 = Long.parseLong(st.nextToken());
            long B1 = Long.parseLong(st.nextToken());
            long B2 = Long.parseLong(st.nextToken());
            long sum = (A1 - A2) + (B1 - B2);
            sb.append(sum < 0 ? "YES" : "NO");
            if (i + 1 < T) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        A1 = int(next(it)); A2 = int(next(it)); B1 = int(next(it)); B2 = int(next(it))
        total = (A1 - A2) + (B1 - B2)
        out_lines.append('YES' if total < 0 else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

